/bin/zsh -lc "python - <<'PY'
import csv, json
from decimal import Decimal, ROUND_HALF_UP
PERF_MULT = {\"S\": 3.0, \"A\": 2.0, \"B\": 1.0}
def team_mult(team_avg):
    if team_avg >= 3.5:
        return 1.2
    elif team_avg >= 2.5:
        return 1.0
    else:
        return 0.8
def seniority_mult(years):
    if years >= 10:
        return 1.5
    elif years >= 5:
        return 1.2
    elif years >= 3:
        return 1.0
    elif years >= 1:
        return 0.8
    else:
        return 0.5
def py_round(x):
    return round(x)
rows=[]
with open('input.csv', newline='', encoding='utf-8') as f:
    for emp in csv.DictReader(f):
        if emp['performance'] == 'C' or float(emp['months_worked']) < 6:
            bonus=0
        else:
            base=float(emp['base_salary'])
            raw=base*PERF_MULT[emp['performance']]*team_mult(float(emp['team_avg_score']))*seniority_mult(float(emp['seniority_years']))*(float(emp['months_worked'])/12)
            bonus=round(min(raw, base*4))
        rows.append({'id': emp['id'], 'bonus': bonus})
print(json.dumps(rows, ensure_ascii=False, indent=2))
PY"

